     1→package tools
     2→
     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"fmt"
     7→
     8→	iafv1alpha1 "github.com/dlapiduz/iaf/api/v1alpha1"
     9→	iafk8s "github.com/dlapiduz/iaf/internal/k8s"
    10→	"github.com/dlapiduz/iaf/internal/validation"
    11→	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
    12→	corev1 "k8s.io/api/core/v1"
    13→	apierrors "k8s.io/apimachinery/pkg/api/errors"
    14→	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    15→	"sigs.k8s.io/controller-runtime/pkg/client"
    16→)
    17→
    18→type DeployAppInput struct {
    19→	SessionID     string               `json:"session_id" jsonschema:"required - session ID returned by the register tool"`
    20→	Name          string               `json:"name" jsonschema:"required - application name (lowercase, hyphens allowed, becomes part of URL)"`
    21→	Image         string               `json:"image,omitempty" jsonschema:"container image to deploy (e.g. 'nginx:latest') - provide either image or git_url"`
    22→	GitURL        string               `json:"git_url,omitempty" jsonschema:"git repository URL to build from (e.g. 'https://github.com/user/repo') - provide either image or git_url"`
    23→	GitRevision   string               `json:"git_revision,omitempty" jsonschema:"git branch, tag, or commit (default: main)"`
    24→	GitCredential string               `json:"git_credential,omitempty" jsonschema:"name of a git credential (from add_git_credential) to use when cloning a private repository"`
    25→	Port          int32                `json:"port,omitempty" jsonschema:"port your app listens on (default: 8080)"`
    26→	Replicas      int32                `json:"replicas,omitempty" jsonschema:"number of replicas (default: 1)"`
    27→	Env           []iafv1alpha1.EnvVar `json:"env,omitempty" jsonschema:"environment variables as [{name, value}]"`
    28→}
    29→
    30→func RegisterDeployApp(server *gomcp.Server, deps *Dependencies) {
    31→	gomcp.AddTool(server, &gomcp.Tool{
    32→		Name:        "deploy_app",
    33→		Description: "Deploy an application from a pre-built container image or git repository. Requires session_id from the register tool. Provide either 'image' (e.g. 'nginx:latest') or 'git_url' (e.g. 'https://github.com/user/repo'). The app will be available at http://<name>.<base-domain> once running. Default port: 8080.",
    34→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input DeployAppInput) (*gomcp.CallToolResult, any, error) {
    35→		namespace, err := deps.ResolveNamespace(input.SessionID)
    36→		if err != nil {
    37→			return nil, nil, err
    38→		}
    39→		if err := validation.ValidateAppName(input.Name); err != nil {
    40→			return nil, nil, err
    41→		}
    42→		for _, e := range input.Env {
    43→			if err := validation.ValidateEnvVarName(e.Name); err != nil {
    44→				return nil, nil, err
    45→			}
    46→		}
    47→		if input.Image == "" && input.GitURL == "" {
    48→			return nil, nil, fmt.Errorf("either image or git_url is required")
    49→		}
    50→
    51→		// Validate git_credential if provided: the Secret must exist in the session namespace
    52→		// and must be an IAF-managed git credential.
    53→		if input.GitCredential != "" {
    54→			credSecret := &corev1.Secret{}
    55→			if err := deps.Client.Get(ctx, client.ObjectKey{Namespace: namespace, Name: input.GitCredential}, credSecret); err != nil {
    56→				if apierrors.IsNotFound(err) {
    57→					return nil, nil, fmt.Errorf("git credential %q not found; create it with add_git_credential first", input.GitCredential)
    58→				}
    59→				return nil, nil, fmt.Errorf("looking up git credential: %w", err)
    60→			}
    61→			if credSecret.Labels[iafk8s.LabelCredentialType] != "git" {
    62→				return nil, nil, fmt.Errorf("secret %q is not a git credential managed by IAF", input.GitCredential)
    63→			}
    64→		}
    65→
    66→		if err := deps.CheckAppNameAvailable(ctx, input.Name, namespace); err != nil {
    67→			return nil, nil, err
    68→		}
    69→
    70→		app := &iafv1alpha1.Application{
    71→			ObjectMeta: metav1.ObjectMeta{
    72→				Name:      input.Name,
    73→				Namespace: namespace,
    74→			},
    75→			Spec: iafv1alpha1.ApplicationSpec{
    76→				Image:    input.Image,
    77→				Port:     input.Port,
    78→				Replicas: input.Replicas,
    79→				Env:      input.Env,
    80→			},
    81→		}
    82→
    83→		if input.GitURL != "" {
    84→			revision := input.GitRevision
    85→			if revision == "" {
    86→				revision = "main"
    87→			}
    88→			app.Spec.Git = &iafv1alpha1.GitSource{
    89→				URL:      input.GitURL,
    90→				Revision: revision,
    91→			}
    92→		}
    93→
    94→		if app.Spec.Port == 0 {
    95→			app.Spec.Port = 8080
    96→		}
    97→		if app.Spec.Replicas == 0 {
    98→			app.Spec.Replicas = 1
    99→		}
   100→
   101→		if err := deps.Client.Create(ctx, app); err != nil {
   102→			if apierrors.IsAlreadyExists(err) {
   103→				return nil, nil, fmt.Errorf("application %q already exists", input.Name)
   104→			}
   105→			return nil, nil, fmt.Errorf("creating application: %w", err)
   106→		}
   107→
   108→		host := fmt.Sprintf("%s.%s", input.Name, deps.BaseDomain)
   109→		result := map[string]any{
   110→			"name":    input.Name,
   111→			"status":  "created",
   112→			"message": fmt.Sprintf("Application %q created successfully. It will be available at https://%s once deployed (TLS enabled by default).", input.Name, host),
   113→		}
   114→		if input.GitURL != "" {
   115→			result["source"] = "git"
   116→			result["buildRequired"] = true
   117→		} else {
   118→			result["source"] = "image"
   119→			result["buildRequired"] = false
   120→		}
   121→
   122→		text, _ := json.MarshalIndent(result, "", "  ")
   123→		return &gomcp.CallToolResult{
   124→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   125→		}, nil, nil
   126→	})
   127→}
   128→

