    18→type PushCodeInput struct {
    19→	SessionID string               `json:"session_id" jsonschema:"required - session ID returned by the register tool"`
    20→	Name      string               `json:"name" jsonschema:"required - application name (lowercase, hyphens allowed, becomes part of URL)"`
    21→	Files     map[string]string    `json:"files" jsonschema:"required - map of file paths to file contents, e.g. {\"main.go\": \"package main...\", \"go.mod\": \"module app...\"}"`
    22→	Port      int32                `json:"port,omitempty" jsonschema:"port your app listens on (default: 8080)"`
    23→	Env       []iafv1alpha1.EnvVar `json:"env,omitempty" jsonschema:"environment variables as [{name, value}]"`
    24→}
    25→
    26→func RegisterPushCode(server *gomcp.Server, deps *Dependencies) {
    27→	gomcp.AddTool(server, &gomcp.Tool{
    28→		Name:        "push_code",
    29→		Description: `Upload source code and automatically build and deploy it as an application. Requires session_id from the register tool. The 'files' parameter is a JSON object mapping file paths to their contents, e.g. {"main.go": "package main\n...", "go.mod": "module myapp\n..."}. The platform auto-detects the language (Go, Node.js, Python, Java, Ruby) and builds a container. Your app must listen on the specified port (default 8080). Use app_status to monitor build progress (~2 min).`,
    30→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input PushCodeInput) (*gomcp.CallToolResult, any, error) {
    31→		namespace, err := deps.ResolveNamespace(input.SessionID)
    32→		if err != nil {
    33→			return nil, nil, err
    34→		}
    35→		if err := validation.ValidateAppName(input.Name); err != nil {
    36→			return nil, nil, err
    37→		}
    38→		for _, e := range input.Env {
    39→			if err := validation.ValidateEnvVarName(e.Name); err != nil {
    40→				return nil, nil, err
    41→			}
    42→		}
    43→		if len(input.Files) == 0 {
    44→			return nil, nil, fmt.Errorf("files map is required")
    45→		}
    46→
    47→		// Store source files — append revision to URL so kpack detects changes
    48→		blobURL, err := deps.Store.StoreFiles(namespace, input.Name, input.Files)
    49→		if err != nil {
    50→			return nil, nil, fmt.Errorf("storing source files: %w", err)
    51→		}
    52→		blobURL = blobURL + "?rev=" + strconv.FormatInt(time.Now().UnixNano(), 36)
    53→
    54→		port := input.Port
    55→		if port == 0 {
    56→			port = 8080
    57→		}
    58→
    59→		// Check if application already exists
    60→		var existing iafv1alpha1.Application
    61→		err = deps.Client.Get(ctx, types.NamespacedName{Name: input.Name, Namespace: namespace}, &existing)
    62→		if err == nil {
    63→			// Update existing application
    64→			existing.Spec.Blob = blobURL
    65→			existing.Spec.Image = ""
    66→			existing.Spec.Git = nil
    67→			existing.Spec.Port = port
    68→			if input.Env != nil {
    69→				existing.Spec.Env = input.Env
    70→			}
    71→			if err := deps.Client.Update(ctx, &existing); err != nil {
    72→				return nil, nil, fmt.Errorf("updating application: %w", err)
    73→			}
    74→		} else if apierrors.IsNotFound(err) {
    75→			// Check name availability before creating
    76→			if err := deps.CheckAppNameAvailable(ctx, input.Name, namespace); err != nil {
    77→				return nil, nil, err
    78→			}
    79→			// Create new application
    80→			app := &iafv1alpha1.Application{
    81→				ObjectMeta: metav1.ObjectMeta{
    82→					Name:      input.Name,
    83→					Namespace: namespace,
    84→				},
    85→				Spec: iafv1alpha1.ApplicationSpec{
    86→					Blob:     blobURL,
    87→					Port:     port,
    88→					Replicas: 1,
    89→					Env:      input.Env,
    90→				},
    91→			}
    92→			if err := deps.Client.Create(ctx, app); err != nil {
    93→				return nil, nil, fmt.Errorf("creating application: %w", err)
    94→			}
    95→		} else {
    96→			return nil, nil, fmt.Errorf("checking application: %w", err)
    97→		}
    98→
    99→		host := fmt.Sprintf("%s.%s", input.Name, deps.BaseDomain)
   100→		result := map[string]any{
   101→			"name":    input.Name,
   102→			"status":  "building",
   103→			"files":   len(input.Files),
   104→			"message": fmt.Sprintf("Source code uploaded and build started for %q. IMPORTANT: The build takes about 2 minutes. Wait at least 90 seconds before checking status. Then use app_status with name %q to check progress. Do NOT poll repeatedly — check once after 90s, then once more after another 30s if still building. Once status is Running, the app will be available at http://%s.", input.Name, input.Name, host),
   105→		}
   106→
   107→		text, _ := json.MarshalIndent(result, "", "  ")
   108→		return &gomcp.CallToolResult{
   109→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   110→		}, nil, nil
   111→	})
   112→}
