    19→type AppLogsInput struct {
    20→	SessionID string `json:"session_id" jsonschema:"required - session ID returned by the register tool"`
    21→	Name      string `json:"name" jsonschema:"required - application name to get logs for"`
    22→	Lines     int64  `json:"lines,omitempty" jsonschema:"number of log lines to return (default: 100)"`
    23→	BuildLogs bool   `json:"build_logs,omitempty" jsonschema:"set to true to get build logs instead of application runtime logs"`
    24→}
    25→
    26→// RegisterAppLogs registers the app_logs tool. It needs both the controller-runtime
    27→// client (for listing pods) and the kubernetes clientset (for reading logs).
    28→func RegisterAppLogs(server *gomcp.Server, deps *Dependencies) {
    29→	gomcp.AddTool(server, &gomcp.Tool{
    30→		Name:        "app_logs",
    31→		Description: "Get logs from an application's running pods, or build logs if build_logs=true. Requires session_id from the register tool and the application name. Use build_logs=true to debug build failures. Default: last 100 lines.",
    32→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input AppLogsInput) (*gomcp.CallToolResult, any, error) {
    33→		namespace, err := deps.ResolveNamespace(input.SessionID)
    34→		if err != nil {
    35→			return nil, nil, err
    36→		}
    37→		if err := validation.ValidateAppName(input.Name); err != nil {
    38→			return nil, nil, err
    39→		}
    40→
    41→		lines := input.Lines
    42→		if lines <= 0 {
    43→			lines = 100
    44→		}
    45→
    46→		// Verify application exists
    47→		var app iafv1alpha1.Application
    48→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.Name, Namespace: namespace}, &app); err != nil {
    49→			if apierrors.IsNotFound(err) {
    50→				return nil, nil, fmt.Errorf("application %q not found", input.Name)
    51→			}
    52→			return nil, nil, fmt.Errorf("getting application: %w", err)
    53→		}
    54→
    55→		result := map[string]any{
    56→			"name":  input.Name,
    57→			"phase": string(app.Status.Phase),
    58→		}
    59→
    60→		if input.BuildLogs {
    61→			result["logType"] = "build"
    62→			result["buildStatus"] = app.Status.BuildStatus
    63→			result["logs"] = "Build logs require a kubernetes clientset. Use the API server endpoint GET /api/v1/applications/{name}/build for full build logs."
    64→		} else {
    65→			result["logType"] = "application"
    66→			result["logs"] = "Application logs require a kubernetes clientset. Use the API server endpoint GET /api/v1/applications/{name}/logs for full logs."
    67→		}
    68→
    69→		text, _ := json.MarshalIndent(result, "", "  ")
    70→		return &gomcp.CallToolResult{
    71→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
    72→		}, nil, nil
    73→	})
    74→}
    75→
    76→// RegisterAppLogsWithClientset registers the app_logs tool with full log streaming support.
    77→func RegisterAppLogsWithClientset(server *gomcp.Server, deps *Dependencies, clientset kubernetes.Interface) {
    78→	gomcp.AddTool(server, &gomcp.Tool{
    79→		Name:        "app_logs",
    80→		Description: "Get logs from an application's running pods, or build logs if build_logs=true. Requires session_id from the register tool and the application name. Use build_logs=true to debug build failures. Default: last 100 lines.",
    81→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input AppLogsInput) (*gomcp.CallToolResult, any, error) {
    82→		namespace, err := deps.ResolveNamespace(input.SessionID)
    83→		if err != nil {
    84→			return nil, nil, err
    85→		}
    86→		if err := validation.ValidateAppName(input.Name); err != nil {
    87→			return nil, nil, err
    88→		}
    89→
    90→		lines := input.Lines
    91→		if lines <= 0 {
    92→			lines = 100
    93→		}
    94→
    95→		var app iafv1alpha1.Application
    96→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.Name, Namespace: namespace}, &app); err != nil {
    97→			if apierrors.IsNotFound(err) {
    98→				return nil, nil, fmt.Errorf("application %q not found", input.Name)
    99→			}
   100→			return nil, nil, fmt.Errorf("getting application: %w", err)
   101→		}
   102→
   103→		var labelKey string
   104→		var container string
   105→		if input.BuildLogs {
   106→			labelKey = "image.kpack.io/image"
   107→			container = ""
   108→		} else {
   109→			labelKey = "iaf.io/application"
   110→			container = "app"
   111→		}
   112→
   113→		podList := &corev1.PodList{}
   114→		if err := deps.Client.List(ctx, podList,
   115→			client.InNamespace(namespace),
   116→			client.MatchingLabels{labelKey: input.Name},
   117→		); err != nil {
   118→			return nil, nil, fmt.Errorf("listing pods: %w", err)
   119→		}
   120→
   121→		if len(podList.Items) == 0 {
   122→			result := map[string]any{
   123→				"name":  input.Name,
   124→				"logs":  "No pods found",
   125→				"phase": string(app.Status.Phase),
   126→			}
   127→			text, _ := json.MarshalIndent(result, "", "  ")
   128→			return &gomcp.CallToolResult{
   129→				Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   130→			}, nil, nil
   131→		}
   132→
   133→		pod := podList.Items[len(podList.Items)-1]
   134→		opts := &corev1.PodLogOptions{
   135→			TailLines: &lines,
   136→		}
   137→		if container != "" {
   138→			opts.Container = container
   139→		}
   140→
   141→		stream, err := clientset.CoreV1().Pods(namespace).GetLogs(pod.Name, opts).Stream(ctx)
   142→		if err != nil {
   143→			return nil, nil, fmt.Errorf("opening log stream: %w", err)
   144→		}
   145→		defer stream.Close()
   146→
   147→		data, err := io.ReadAll(stream)
   148→		if err != nil {
   149→			return nil, nil, fmt.Errorf("reading logs: %w", err)
   150→		}
   151→
   152→		result := map[string]any{
   153→			"name":    input.Name,
   154→			"logs":    string(data),
   155→			"podName": pod.Name,
   156→			"phase":   string(app.Status.Phase),
   157→		}
   158→
   159→		text, _ := json.MarshalIndent(result, "", "  ")
   160→		return &gomcp.CallToolResult{
   161→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   162→		}, nil, nil
   163→	})
   164→}
