    20→// rejectedSecretTypes are Secret types that must never be copied into session namespaces.
    21→var rejectedSecretTypes = map[corev1.SecretType]bool{
    22→	corev1.SecretTypeServiceAccountToken: true,
    23→	corev1.SecretTypeDockerConfigJson:    true,
    24→	corev1.SecretTypeDockercfg:           true,
    25→}
    26→
    27→// dsSecretName returns the name to use for the copied credential Secret in the session namespace.
    28→// Prefixed with "iaf-ds-" and truncated to 63 characters (Kubernetes DNS label limit).
    29→func dsSecretName(dataSourceName string) string {
    30→	name := "iaf-ds-" + dataSourceName
    31→	if len(name) > 63 {
    32→		name = name[:63]
    33→	}
    34→	return name
    35→}
    36→
    37→// ---- list_data_sources -------------------------------------------------------
    38→
    39→type ListDataSourcesInput struct {
    40→	SessionID string `json:"session_id" jsonschema:"required - session ID returned by the register tool"`
    41→	Kind      string `json:"kind,omitempty" jsonschema:"filter by data source kind (e.g. postgres, mysql, s3)"`
    42→	Tags      string `json:"tags,omitempty" jsonschema:"comma-separated list of tags to filter by (all must match)"`
    43→}
    44→
    45→// RegisterListDataSources registers the list_data_sources MCP tool.
    46→func RegisterListDataSources(server *gomcp.Server, deps *Dependencies) {
    47→	gomcp.AddTool(server, &gomcp.Tool{
    48→		Name:        "list_data_sources",
    49→		Description: "List all data sources registered on the platform. Returns metadata only — no credentials are returned. Optionally filter by kind or tags. Use get_data_source for details on a specific source, and attach_data_source to make one available to your app.",
    50→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input ListDataSourcesInput) (*gomcp.CallToolResult, any, error) {
    51→		if _, err := deps.ResolveNamespace(input.SessionID); err != nil {
    52→			return nil, nil, err
    53→		}
    54→
    55→		var list iafv1alpha1.DataSourceList
    56→		if err := deps.Client.List(ctx, &list); err != nil {
    57→			return nil, nil, fmt.Errorf("listing data sources: %w", err)
    58→		}
    59→
    60→		// Parse tag filter.
    61→		var filterTags []string
    62→		if input.Tags != "" {
    63→			for _, t := range strings.Split(input.Tags, ",") {
    64→				if t = strings.TrimSpace(t); t != "" {
    65→					filterTags = append(filterTags, t)
    66→				}
    67→			}
    68→		}
    69→
    70→		var entries []map[string]any
    71→		for _, ds := range list.Items {
    72→			if input.Kind != "" && ds.Spec.Kind != input.Kind {
    73→				continue
    74→			}
    75→			if len(filterTags) > 0 && !hasAllTags(ds.Spec.Tags, filterTags) {
    76→				continue
    77→			}
    78→
    79→			envVarNames := envVarNamesFromMapping(ds.Spec.EnvVarMapping)
    80→			entry := map[string]any{
    81→				"name":        ds.Name,
    82→				"kind":        ds.Spec.Kind,
    83→				"envVarNames": envVarNames,
    84→			}
    85→			if ds.Spec.Description != "" {
    86→				entry["description"] = ds.Spec.Description
    87→			}
    88→			if len(ds.Spec.Tags) > 0 {
    89→				entry["tags"] = ds.Spec.Tags
    90→			}
    91→			entries = append(entries, entry)
    92→		}
    93→		if entries == nil {
    94→			entries = []map[string]any{}
    95→		}
    96→
    97→		text, _ := json.MarshalIndent(map[string]any{
    98→			"dataSources": entries,
    99→			"total":       len(entries),
   100→		}, "", "  ")
   101→		return &gomcp.CallToolResult{
   102→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   103→		}, nil, nil
   104→	})
   105→}
