   159→
   160→type AttachDataSourceInput struct {
   161→	SessionID      string `json:"session_id" jsonschema:"required - session ID returned by the register tool"`
   162→	AppName        string `json:"app_name" jsonschema:"required - name of the application to attach the data source to"`
   163→	DataSourceName string `json:"datasource_name" jsonschema:"required - name of the data source to attach"`
   164→}
   165→
   166→// RegisterAttachDataSource registers the attach_data_source MCP tool.
   167→func RegisterAttachDataSource(server *gomcp.Server, deps *Dependencies) {
   168→	gomcp.AddTool(server, &gomcp.Tool{
   169→		Name:        "attach_data_source",
   170→		Description: "Attach a data source to an application. The platform copies the data source credentials into your namespace and injects them as environment variables into the app container. The app will restart to pick up the new variables. Credential values are never returned.",
   171→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input AttachDataSourceInput) (*gomcp.CallToolResult, any, error) {
   172→		namespace, err := deps.ResolveNamespace(input.SessionID)
   173→		if err != nil {
   174→			return nil, nil, err
   175→		}
   176→
   177→		if err := iafvalidation.ValidateAppName(input.AppName); err != nil {
   178→			return nil, nil, fmt.Errorf("invalid app_name: %w", err)
   179→		}
   180→		if input.DataSourceName == "" {
   181→			return nil, nil, fmt.Errorf("datasource_name is required")
   182→		}
   183→
   184→		// Get the Application CR.
   185→		var app iafv1alpha1.Application
   186→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.AppName, Namespace: namespace}, &app); err != nil {
   187→			if apierrors.IsNotFound(err) {
   188→				return nil, nil, fmt.Errorf("application %q not found in your session namespace; use list_apps to see your apps", input.AppName)
   189→			}
   190→			return nil, nil, fmt.Errorf("getting application: %w", err)
   191→		}
   192→
   193→		// Idempotency: if already attached, return success.
   194→		for _, ads := range app.Spec.AttachedDataSources {
   195→			if ads.DataSourceName == input.DataSourceName {
   196→				envVarNames := []string{}
   197→				// Re-fetch DataSource to return accurate env var names.
   198→				var ds iafv1alpha1.DataSource
   199→				if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.DataSourceName}, &ds); err == nil {
   200→					envVarNames = envVarNamesFromMapping(ds.Spec.EnvVarMapping)
   201→				}
   202→				result := map[string]any{
   203→					"datasource":  input.DataSourceName,
   204→					"app":         input.AppName,
   205→					"envVarNames": envVarNames,
   206→					"message":     fmt.Sprintf("Data source %q is already attached to app %q.", input.DataSourceName, input.AppName),
   207→					"alreadyAttached": true,
   208→				}
   209→				text, _ := json.MarshalIndent(result, "", "  ")
   210→				return &gomcp.CallToolResult{
   211→					Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   212→				}, nil, nil
   213→			}
   214→		}
   215→
   216→		// Get DataSource CR (cluster-scoped, no namespace).
   217→		var ds iafv1alpha1.DataSource
   218→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.DataSourceName}, &ds); err != nil {
   219→			if apierrors.IsNotFound(err) {
   220→				return nil, nil, fmt.Errorf("data source %q not found; use list_data_sources to see available sources", input.DataSourceName)
   221→			}
   222→			return nil, nil, fmt.Errorf("getting data source: %w", err)
   223→		}
   224→
   225→		// Check env var collisions.
   226→		if err := checkEnvVarCollisions(ctx, deps.Client, &app, &ds); err != nil {
   227→			return nil, nil, err
   228→		}
   229→
   230→		// Get source Secret from the operator-specified namespace.
   231→		var srcSecret corev1.Secret
   232→		if err := deps.Client.Get(ctx, types.NamespacedName{
   233→			Name:      ds.Spec.SecretRef.Name,
   234→			Namespace: ds.Spec.SecretRef.Namespace,
   235→		}, &srcSecret); err != nil {
   236→			if apierrors.IsNotFound(err) {
   237→				return nil, nil, fmt.Errorf("data source %q credential secret not found — contact your platform administrator", input.DataSourceName)
   238→			}
   239→			return nil, nil, fmt.Errorf("reading data source credentials: %w", err)
   240→		}
   241→
   242→		// Validate source Secret type.
   243→		if rejectedSecretTypes[srcSecret.Type] {
   244→			return nil, nil, fmt.Errorf("data source %q references a secret of type %q which is not allowed for use as a data source credential", input.DataSourceName, srcSecret.Type)
   245→		}
   246→
   247→		// Create a copy of the Secret in the session namespace, owned by the Application.
   248→		secretName := dsSecretName(input.DataSourceName)
   249→		copiedSecret := &corev1.Secret{
   250→			ObjectMeta: metav1.ObjectMeta{
   251→				Name:      secretName,
   252→				Namespace: namespace,
   253→				Labels: map[string]string{
   254→					"app.kubernetes.io/managed-by": "iaf",
   255→					"iaf.io/datasource":            input.DataSourceName,
   256→				},
   257→				OwnerReferences: []metav1.OwnerReference{
   258→					{
   259→						APIVersion: iafv1alpha1.GroupVersion.String(),
   260→						Kind:       "Application",
   261→						Name:       app.Name,
   262→						UID:        app.UID,
   263→						Controller: boolPtrDS(true),
   264→					},
   265→				},
   266→			},
   267→			Type: srcSecret.Type,
   268→			Data: srcSecret.Data,
   269→		}
   270→
   271→		existingCopy := &corev1.Secret{}
   272→		getErr := deps.Client.Get(ctx, types.NamespacedName{Name: secretName, Namespace: namespace}, existingCopy)
   273→		if getErr != nil && !apierrors.IsNotFound(getErr) {
   274→			return nil, nil, fmt.Errorf("checking for existing credential copy: %w", getErr)
   275→		}
   276→		if apierrors.IsNotFound(getErr) {
   277→			if err := deps.Client.Create(ctx, copiedSecret); err != nil {
   278→				return nil, nil, fmt.Errorf("copying data source credentials: %w", err)
   279→			}
   280→		}
   281→		// If the Secret already exists (e.g., from a previous partial attach), reuse it.
   282→
   283→		// Patch the Application CR to record the attachment.
   284→		original := app.DeepCopy()
   285→		app.Spec.AttachedDataSources = append(app.Spec.AttachedDataSources, iafv1alpha1.AttachedDataSource{
   286→			DataSourceName: input.DataSourceName,
   287→			SecretName:     secretName,
   288→		})
   289→		if err := deps.Client.Patch(ctx, &app, client.MergeFrom(original)); err != nil {
   290→			// Clean up the copied Secret on patch failure to avoid orphans.
   291→			if apierrors.IsNotFound(getErr) { // only delete if we just created it
   292→				_ = deps.Client.Delete(ctx, copiedSecret)
   293→			}
   294→			return nil, nil, fmt.Errorf("attaching data source to application: %w", err)
   295→		}
   296→
   297→		// Audit log: every attachment is logged.
   298→		slog.Info("data source attached",
   299→			"session", input.SessionID,
   300→			"datasource", input.DataSourceName,
   301→			"app", input.AppName,
   302→			"namespace", namespace,
   303→		)
   304→
   305→		envVarNames := envVarNamesFromMapping(ds.Spec.EnvVarMapping)
   306→		result := map[string]any{
   307→			"datasource":  input.DataSourceName,
   308→			"app":         input.AppName,
   309→			"envVarNames": envVarNames,
   310→			"message":     fmt.Sprintf("Data source %q attached to app %q. The app will restart to pick up the new environment variables: %v.", input.DataSourceName, input.AppName, envVarNames),
   311→		}
   312→		text, _ := json.MarshalIndent(result, "", "  ")
   313→		return &gomcp.CallToolResult{
   314→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   315→		}, nil, nil
   316→	})
   317→}
   318→
   319→// checkEnvVarCollisions returns an error if any env var in ds.Spec.EnvVarMapping
   320→// collides with env vars in app.Spec.Env or in already-attached data sources.
   321→func checkEnvVarCollisions(ctx context.Context, k8sClient client.Client, app *iafv1alpha1.Application, ds *iafv1alpha1.DataSource) error {
   322→	// Build a map of already-used env var names → source label.
   323→	used := map[string]string{}
   324→
   325→	for _, e := range app.Spec.Env {
   326→		used[e.Name] = "app env var"
   327→	}
   328→
   329→	for _, ads := range app.Spec.AttachedDataSources {
   330→		var existingDS iafv1alpha1.DataSource
   331→		if err := k8sClient.Get(ctx, types.NamespacedName{Name: ads.DataSourceName}, &existingDS); err != nil {
   332→			// If the existing DataSource is gone, skip — no collision possible.
   333→			continue
   334→		}
   335→		for _, envVarName := range existingDS.Spec.EnvVarMapping {
   336→			used[envVarName] = fmt.Sprintf("data source %q", ads.DataSourceName)
   337→		}
   338→	}
   339→
   340→	for _, envVarName := range ds.Spec.EnvVarMapping {
   341→		if source, conflict := used[envVarName]; conflict {
   342→			return fmt.Errorf("env var %q is already defined by %s; choose a data source that uses different variable names or detach the conflicting source first", envVarName, source)
   343→		}
   344→	}
   345→	return nil
   346→}
   347→
   348→// envVarNamesFromMapping returns a sorted slice of env var names from a mapping.
   349→func envVarNamesFromMapping(mapping map[string]string) []string {
   350→	names := make([]string, 0, len(mapping))
   351→	for _, v := range mapping {
   352→		names = append(names, v)
   353→	}
   354→	return names
   355→}
   356→
   357→// hasAllTags returns true if item contains every tag in required.
   358→func hasAllTags(itemTags, required []string) bool {
   359→	tagSet := make(map[string]bool, len(itemTags))
   360→	for _, t := range itemTags {
   361→		tagSet[t] = true
   362→	}
   363→	for _, t := range required {
   364→		if !tagSet[t] {
   365→			return false
   366→		}
   367→	}
   368→	return true
   369→}
   370→
   371→// boolPtrDS is a local helper to avoid import cycle with the controller package.
   372→func boolPtrDS(b bool) *bool { return &b }
