    18→func RegisterListApps(server *gomcp.Server, deps *Dependencies) {
    19→	gomcp.AddTool(server, &gomcp.Tool{
    20→		Name:        "list_apps",
    21→		Description: "List all applications in your session's workspace with their current status, source type, and URLs. Requires session_id from the register tool. Optionally filter by status (Pending, Building, Deploying, Running, Failed).",
    22→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input ListAppsInput) (*gomcp.CallToolResult, any, error) {
    23→		namespace, err := deps.ResolveNamespace(input.SessionID)
    24→		if err != nil {
    25→			return nil, nil, err
    26→		}
    27→
    28→		var list iafv1alpha1.ApplicationList
    29→		if err := deps.Client.List(ctx, &list, client.InNamespace(namespace)); err != nil {
    30→			return nil, nil, fmt.Errorf("listing applications: %w", err)
    31→		}
    32→
    33→		var apps []map[string]any
    34→		for _, app := range list.Items {
    35→			if input.Status != "" && string(app.Status.Phase) != input.Status {
    36→				continue
    37→			}
    38→
    39→			entry := map[string]any{
    40→				"name":              app.Name,
    41→				"phase":             string(app.Status.Phase),
    42→				"url":               app.Status.URL,
    43→				"availableReplicas": app.Status.AvailableReplicas,
    44→				"replicas":          app.Spec.Replicas,
    45→			}
    46→
    47→			if app.Spec.Image != "" {
    48→				entry["sourceType"] = "image"
    49→			} else if app.Spec.Git != nil {
    50→				entry["sourceType"] = "git"
    51→			} else if app.Spec.Blob != "" {
