    57→			}
    58→
    59→			apps = append(apps, entry)
    60→		}
    61→
    62→		if apps == nil {
    63→			apps = []map[string]any{}
    64→		}
    65→
    66→		result := map[string]any{
    67→			"applications": apps,
    68→			"total":        len(apps),
    69→		}
