    71→		text, _ := json.MarshalIndent(result, "", "  ")
    72→		return &gomcp.CallToolResult{
    73→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
    74→		}, nil, nil
    75→	})
    76→}
