    18→
    19→const (
    20→	maxCredentialsPerSession = 20
    21→	maxPasswordLen           = 4096
    22→	maxSSHKeyLen             = 16 * 1024
    23→)
    24→
    25→// AddGitCredentialInput is the input for the add_git_credential tool.
    26→type AddGitCredentialInput struct {
    27→	SessionID    string `json:"session_id"    jsonschema:"required - session ID from the register tool"`
    28→	Name         string `json:"name"          jsonschema:"required - credential name (DNS label: lowercase alphanumeric and hyphens)"`
    29→	Type         string `json:"type"          jsonschema:"required - credential type: 'basic-auth' or 'ssh'"`
    30→	GitServerURL string `json:"git_server_url" jsonschema:"required - server URL to associate credential with (https://... for basic-auth, git@<host> for ssh)"`
    31→	// basic-auth fields
    32→	Username string `json:"username,omitempty" jsonschema:"username (required for basic-auth)"`
    33→	Password string `json:"password,omitempty" jsonschema:"password or token (required for basic-auth, max 4096 bytes)"`
    34→	// ssh field
    35→	PrivateKey string `json:"private_key,omitempty" jsonschema:"PEM-encoded SSH private key (required for ssh, max 16 KB)"`
    36→}
    37→
    38→// ListGitCredentialsInput is the input for the list_git_credentials tool.
    39→type ListGitCredentialsInput struct {
    40→	SessionID string `json:"session_id" jsonschema:"required - session ID from the register tool"`
    41→}
    42→
    43→// DeleteGitCredentialInput is the input for the delete_git_credential tool.
    44→type DeleteGitCredentialInput struct {
    45→	SessionID string `json:"session_id" jsonschema:"required - session ID from the register tool"`
    46→	Name      string `json:"name"       jsonschema:"required - credential name to delete"`
    47→}
    48→
    49→// RegisterAddGitCredential registers the add_git_credential MCP tool.
    50→func RegisterAddGitCredential(server *gomcp.Server, deps *Dependencies) {
    51→	gomcp.AddTool(server, &gomcp.Tool{
    52→		Name:        "add_git_credential",
    53→		Description: "Store a git credential (username/password or SSH key) in the session namespace so kpack can clone private repositories. Requires session_id. Credential material is never returned in any tool output. To rotate a credential, delete it and re-create it.",
    54→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input AddGitCredentialInput) (*gomcp.CallToolResult, any, error) {
    55→		namespace, err := deps.ResolveNamespace(input.SessionID)
    56→		if err != nil {
    57→			return nil, nil, err
    58→		}
    59→
    60→		// Validate name as DNS label.
    61→		if err := validation.ValidateAppName(input.Name); err != nil {
    62→			return nil, nil, fmt.Errorf("invalid credential name: %w", err)
    63→		}
    64→
    65→		// Validate type allowlist.
    66→		if input.Type != "basic-auth" && input.Type != "ssh" {
    67→			return nil, nil, fmt.Errorf("type must be 'basic-auth' or 'ssh'")
    68→		}
    69→
    70→		// Type-specific validation.
    71→		switch input.Type {
    72→		case "basic-auth":
    73→			if err := validation.ValidateBasicAuthGitServerURL(input.GitServerURL); err != nil {
    74→				return nil, nil, err
    75→			}
    76→			if input.Username == "" {
    77→				return nil, nil, fmt.Errorf("username is required for basic-auth")
    78→			}
    79→			if input.Password == "" {
    80→				return nil, nil, fmt.Errorf("password is required for basic-auth")
    81→			}
    82→			if len(input.Password) > maxPasswordLen {
    83→				return nil, nil, fmt.Errorf("password must be %d bytes or fewer", maxPasswordLen)
    84→			}
    85→		case "ssh":
    86→			if err := validation.ValidateSSHGitServerURL(input.GitServerURL); err != nil {
    87→				return nil, nil, err
    88→			}
    89→			if input.PrivateKey == "" {
    90→				return nil, nil, fmt.Errorf("private_key is required for ssh")
    91→			}
    92→			if len(input.PrivateKey) > maxSSHKeyLen {
    93→				return nil, nil, fmt.Errorf("private_key must be %d bytes or fewer", maxSSHKeyLen)
    94→			}
    95→			if !strings.HasPrefix(input.PrivateKey, "-----BEGIN ") {
    96→				return nil, nil, fmt.Errorf("private_key must be a PEM-encoded key (must start with '-----BEGIN ...')")
    97→			}
    98→		}
    99→
   100→		// Enforce per-session credential count limit.
   101→		var secretList corev1.SecretList
   102→		if err := deps.Client.List(ctx, &secretList,
   103→			client.InNamespace(namespace),
   104→			client.MatchingLabels{iafk8s.LabelCredentialType: "git"},
   105→		); err != nil {
   106→			return nil, nil, fmt.Errorf("listing git credentials: %w", err)
   107→		}
   108→		if len(secretList.Items) >= maxCredentialsPerSession {
   109→			return nil, nil, fmt.Errorf("credential limit reached: a session may have at most %d git credentials; delete an existing one before adding a new one", maxCredentialsPerSession)
   110→		}
   111→
   112→		// Build and create the Secret.
   113→		secret := iafk8s.BuildGitCredentialSecret(
   114→			namespace, input.Name, input.Type, input.GitServerURL,
   115→			input.Username, input.Password, input.PrivateKey,
   116→		)
   117→		if err := deps.Client.Create(ctx, secret); err != nil {
   118→			if apierrors.IsAlreadyExists(err) {
