   144→// RegisterListGitCredentials registers the list_git_credentials MCP tool.
   145→func RegisterListGitCredentials(server *gomcp.Server, deps *Dependencies) {
   146→	gomcp.AddTool(server, &gomcp.Tool{
   147→		Name:        "list_git_credentials",
   148→		Description: "List all git credentials stored in the current session. Returns name, type, and server URL — never credential material.",
   149→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input ListGitCredentialsInput) (*gomcp.CallToolResult, any, error) {
   150→		namespace, err := deps.ResolveNamespace(input.SessionID)
   151→		if err != nil {
   152→			return nil, nil, err
   153→		}
   154→
   155→		var secretList corev1.SecretList
   156→		if err := deps.Client.List(ctx, &secretList,
   157→			client.InNamespace(namespace),
   158→			client.MatchingLabels{iafk8s.LabelCredentialType: "git"},
   159→		); err != nil {
   160→			return nil, nil, fmt.Errorf("listing git credentials: %w", err)
   161→		}
   162→
   163→		type credInfo struct {
   164→			Name         string `json:"name"`
   165→			Type         string `json:"type"`
   166→			GitServerURL string `json:"git_server_url"`
   167→			CreatedAt    string `json:"created_at"`
   168→		}
   169→		creds := make([]credInfo, 0, len(secretList.Items))
   170→		for _, s := range secretList.Items {
   171→			credType := credTypeFromSecretType(s.Type)
   172→			serverURL := s.Annotations[iafk8s.AnnotationGitServer]
   173→			var createdAt string
   174→			if !s.CreationTimestamp.IsZero() {
   175→				createdAt = s.CreationTimestamp.UTC().Format(time.RFC3339)
   176→			}
   177→			creds = append(creds, credInfo{
   178→				Name:         s.Name,
   179→				Type:         credType,
   180→				GitServerURL: serverURL,
   181→				CreatedAt:    createdAt,
   182→			})
   183→		}
   184→
   185→		result := map[string]any{
   186→			"credentials": creds,
   187→			"total":       len(creds),
   188→		}
   189→		text, _ := json.MarshalIndent(result, "", "  ")
   190→		return &gomcp.CallToolResult{
   191→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   192→		}, nil, nil
   193→	})
   194→}
