   196→// RegisterDeleteGitCredential registers the delete_git_credential MCP tool.
   197→func RegisterDeleteGitCredential(server *gomcp.Server, deps *Dependencies) {
   198→	gomcp.AddTool(server, &gomcp.Tool{
   199→		Name:        "delete_git_credential",
   200→		Description: "Delete a git credential from the current session. Also removes it from the kpack service account so it will no longer be used for builds.",
   201→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input DeleteGitCredentialInput) (*gomcp.CallToolResult, any, error) {
   202→		namespace, err := deps.ResolveNamespace(input.SessionID)
   203→		if err != nil {
   204→			return nil, nil, err
   205→		}
   206→		if input.Name == "" {
   207→			return nil, nil, fmt.Errorf("name is required")
   208→		}
   209→
   210→		// Fetch the Secret and verify it is a git credential (label guard).
   211→		secret := &corev1.Secret{}
   212→		if err := deps.Client.Get(ctx, client.ObjectKey{Namespace: namespace, Name: input.Name}, secret); err != nil {
   213→			if apierrors.IsNotFound(err) {
   214→				return nil, nil, fmt.Errorf("credential %q not found", input.Name)
   215→			}
   216→			return nil, nil, fmt.Errorf("getting credential: %w", err)
   217→		}
   218→		if secret.Labels[iafk8s.LabelCredentialType] != "git" {
   219→			return nil, nil, fmt.Errorf("secret %q is not a git credential managed by IAF", input.Name)
   220→		}
   221→
   222→		// Remove from kpack SA before deleting the Secret.
   223→		if err := iafk8s.RemoveSecretFromKpackSA(ctx, deps.Client, namespace, input.Name); err != nil {
   224→			return nil, nil, fmt.Errorf("removing credential from kpack service account: %w", err)
   225→		}
   226→
   227→		if err := deps.Client.Delete(ctx, &corev1.Secret{
   228→			ObjectMeta: metav1.ObjectMeta{Name: input.Name, Namespace: namespace},
   229→		}); err != nil {
   230→			if apierrors.IsNotFound(err) {
   231→				return nil, nil, fmt.Errorf("credential %q not found", input.Name)
   232→			}
   233→			return nil, nil, fmt.Errorf("deleting credential: %w", err)
   234→		}
   235→
   236→		result := map[string]any{
   237→			"name":    input.Name,
   238→			"deleted": true,
   239→		}
   240→		text, _ := json.MarshalIndent(result, "", "  ")
   241→		return &gomcp.CallToolResult{
   242→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   243→		}, nil, nil
   244→	})
   245→}
