   247→// credTypeFromSecretType converts a Kubernetes secret type to the IAF credential type string.
   248→func credTypeFromSecretType(t corev1.SecretType) string {
   249→	switch t {
   250→	case corev1.SecretTypeBasicAuth:
   251→		return "basic-auth"
   252→	case corev1.SecretTypeSSHAuth:
   253→		return "ssh"
   254→	default:
   255→		return string(t)
   256→	}
   257→}
