   150→	ServiceName string `json:"service_name" jsonschema:"required - name of the managed service"`
   151→	AppName     string `json:"app_name" jsonschema:"required - name of the application to bind to"`
   152→}
   153→
   154→// RegisterBindService registers the bind_service MCP tool.
   155→func RegisterBindService(server *gomcp.Server, deps *Dependencies) {
   156→	gomcp.AddTool(server, &gomcp.Tool{
   157→		Name:        "bind_service",
   158→		Description: "Bind a ready managed service to an application. Injects connection credentials as Kubernetes Secret references into the application's environment variables (DATABASE_URL, PGHOST, PGPORT, PGDATABASE, PGUSER, PGPASSWORD). The service must be in Ready phase.",
   159→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input BindServiceInput) (*gomcp.CallToolResult, any, error) {
   160→		namespace, err := deps.ResolveNamespace(input.SessionID)
   161→		if err != nil {
   162→			return nil, nil, err
   163→		}
   164→		if err := validation.ValidateAppName(input.ServiceName); err != nil {
   165→			return nil, nil, fmt.Errorf("invalid service name: %w", err)
   166→		}
   167→		if err := validation.ValidateAppName(input.AppName); err != nil {
   168→			return nil, nil, fmt.Errorf("invalid app name: %w", err)
   169→		}
   170→
   171→		// Fetch and validate the service.
   172→		var svc iafv1alpha1.ManagedService
   173→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.ServiceName, Namespace: namespace}, &svc); err != nil {
   174→			if apierrors.IsNotFound(err) {
   175→				return nil, nil, fmt.Errorf("service %q not found", input.ServiceName)
   176→			}
   177→			return nil, nil, fmt.Errorf("getting service: %w", err)
   178→		}
   179→		if svc.Status.Phase != iafv1alpha1.ManagedServicePhaseReady {
   180→			return nil, nil, fmt.Errorf("service %q is not ready (phase: %s) — poll service_status until phase is Ready", input.ServiceName, svc.Status.Phase)
   181→		}
   182→
   183→		// Validate the secret name matches the expected CNPG convention.
   184→		expectedSecret := input.ServiceName + "-app"
   185→		if svc.Status.ConnectionSecretRef != expectedSecret {
   186→			return nil, nil, fmt.Errorf("service %q has unexpected connection secret %q (expected %q) — this is a platform error", input.ServiceName, svc.Status.ConnectionSecretRef, expectedSecret)
   187→		}
   188→		secretName := expectedSecret
   189→
   190→		// Fetch and validate the application.
   191→		var app iafv1alpha1.Application
   192→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.AppName, Namespace: namespace}, &app); err != nil {
   193→			if apierrors.IsNotFound(err) {
   194→				return nil, nil, fmt.Errorf("application %q not found", input.AppName)
   195→			}
   196→			return nil, nil, fmt.Errorf("getting application: %w", err)
   197→		}
   198→
   199→		// Check for duplicate binding.
   200→		for _, bms := range app.Spec.BoundManagedServices {
   201→			if bms.ServiceName == input.ServiceName {
   202→				return nil, nil, fmt.Errorf("service %q is already bound to application %q", input.ServiceName, input.AppName)
   203→			}
   204→		}
   205→
   206→		// Record the binding; the controller injects PG* env vars from the Secret.
   207→		app.Spec.BoundManagedServices = append(app.Spec.BoundManagedServices, iafv1alpha1.BoundManagedService{
   208→			ServiceName: input.ServiceName,
   209→			SecretName:  secretName,
   210→		})
   211→		if err := deps.Client.Update(ctx, &app); err != nil {
   212→			return nil, nil, fmt.Errorf("updating application bindings: %w", err)
   213→		}
   214→
   215→		// Update ManagedService.Status.BoundApps with optimistic retry on conflict.
   216→		if err := addBoundApp(ctx, deps.Client, namespace, input.ServiceName, input.AppName); err != nil {
   217→			return nil, nil, err
   218→		}
   219→
   220→		result := map[string]any{
   221→			"bound":            true,
   222→			"injectedEnvVars":  serviceEnvVarNames,
   223→			"message": fmt.Sprintf("Application %q is now bound to service %q. Credentials are injected as K8s Secret references — actual values are never returned by tools.", input.AppName, input.ServiceName),
   224→		}
   225→		text, _ := json.MarshalIndent(result, "", "  ")
   226→		return &gomcp.CallToolResult{
   227→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   228→		}, nil, nil
   229→	})
   230→}
