   240→// RegisterUnbindService registers the unbind_service MCP tool.
   241→func RegisterUnbindService(server *gomcp.Server, deps *Dependencies) {
   242→	gomcp.AddTool(server, &gomcp.Tool{
   243→		Name:        "unbind_service",
   244→		Description: "Remove the binding between a managed service and an application. Removes the injected environment variables from the application. Does not delete the service or its credentials.",
   245→	}, func(ctx context.Context, req *gomcp.CallToolRequest, input UnbindServiceInput) (*gomcp.CallToolResult, any, error) {
   246→		namespace, err := deps.ResolveNamespace(input.SessionID)
   247→		if err != nil {
   248→			return nil, nil, err
   249→		}
   250→		if err := validation.ValidateAppName(input.ServiceName); err != nil {
   251→			return nil, nil, fmt.Errorf("invalid service name: %w", err)
   252→		}
   253→		if err := validation.ValidateAppName(input.AppName); err != nil {
   254→			return nil, nil, fmt.Errorf("invalid app name: %w", err)
   255→		}
   256→
   257→		var svc iafv1alpha1.ManagedService
   258→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.ServiceName, Namespace: namespace}, &svc); err != nil {
   259→			if apierrors.IsNotFound(err) {
   260→				return nil, nil, fmt.Errorf("service %q not found", input.ServiceName)
   261→			}
   262→			return nil, nil, fmt.Errorf("getting service: %w", err)
   263→		}
   264→
   265→		var app iafv1alpha1.Application
   266→		if err := deps.Client.Get(ctx, types.NamespacedName{Name: input.AppName, Namespace: namespace}, &app); err != nil {
   267→			if apierrors.IsNotFound(err) {
   268→				return nil, nil, fmt.Errorf("application %q not found", input.AppName)
   269→			}
   270→			return nil, nil, fmt.Errorf("getting application: %w", err)
   271→		}
   272→
   273→		// Remove this service from BoundManagedServices.
   274→		filtered := make([]iafv1alpha1.BoundManagedService, 0, len(app.Spec.BoundManagedServices))
   275→		for _, bms := range app.Spec.BoundManagedServices {
   276→			if bms.ServiceName != input.ServiceName {
   277→				filtered = append(filtered, bms)
   278→			}
   279→		}
   280→		app.Spec.BoundManagedServices = filtered
   281→		if err := deps.Client.Update(ctx, &app); err != nil {
   282→			return nil, nil, fmt.Errorf("updating application bindings: %w", err)
   283→		}
   284→
   285→		// Remove app from BoundApps with optimistic retry.
   286→		if err := removeBoundApp(ctx, deps.Client, namespace, input.ServiceName, input.AppName); err != nil {
   287→			return nil, nil, err
   288→		}
   289→
   290→		result := map[string]any{
   291→			"unbound": true,
   292→			"message": fmt.Sprintf("Application %q has been unbound from service %q. Removed injected environment variables.", input.AppName, input.ServiceName),
   293→		}
   294→		text, _ := json.MarshalIndent(result, "", "  ")
   295→		return &gomcp.CallToolResult{
   296→			Content: []gomcp.Content{&gomcp.TextContent{Text: string(text)}},
   297→		}, nil, nil
   298→	})
   299→}
