   397→// --- helpers ---
   398→
   399→// addBoundApp adds appName to svc.Status.BoundApps with optimistic-concurrency retry on conflict.
   400→func addBoundApp(ctx context.Context, c client.Client, namespace, svcName, appName string) error {
   401→	for attempt := 0; attempt < 3; attempt++ {
   402→		var svc iafv1alpha1.ManagedService
   403→		if err := c.Get(ctx, types.NamespacedName{Name: svcName, Namespace: namespace}, &svc); err != nil {
   404→			return fmt.Errorf("getting service for bound-apps update: %w", err)
   405→		}
   406→		for _, name := range svc.Status.BoundApps {
   407→			if name == appName {
   408→				return nil // already in the list
   409→			}
   410→		}
   411→		svc.Status.BoundApps = append(svc.Status.BoundApps, appName)
   412→		err := c.Status().Update(ctx, &svc)
   413→		if err == nil {
   414→			return nil
   415→		}
   416→		if !apierrors.IsConflict(err) {
   417→			return fmt.Errorf("updating service bound apps: %w", err)
   418→		}
   419→	}
   420→	return fmt.Errorf("failed to update service bound apps after retries")
   421→}
   422→
   423→// removeBoundApp removes appName from svc.Status.BoundApps with optimistic-concurrency retry.
   424→func removeBoundApp(ctx context.Context, c client.Client, namespace, svcName, appName string) error {
   425→	for attempt := 0; attempt < 3; attempt++ {
   426→		var svc iafv1alpha1.ManagedService
   427→		if err := c.Get(ctx, types.NamespacedName{Name: svcName, Namespace: namespace}, &svc); err != nil {
   428→			if apierrors.IsNotFound(err) {
   429→				return nil // service already gone, nothing to do
   430→			}
   431→			return fmt.Errorf("getting service for bound-apps update: %w", err)
   432→		}
   433→		filtered := make([]string, 0, len(svc.Status.BoundApps))
   434→		for _, name := range svc.Status.BoundApps {
   435→			if name != appName {
   436→				filtered = append(filtered, name)
   437→			}
   438→		}
   439→		svc.Status.BoundApps = filtered
   440→		err := c.Status().Update(ctx, &svc)
   441→		if err == nil {
   442→			return nil
   443→		}
   444→		if !apierrors.IsConflict(err) {
   445→			return fmt.Errorf("updating service bound apps: %w", err)
   446→		}
