    18→		Name:        "data-catalog",
    19→		Description: "JSON index of all data sources registered on the platform. Contains metadata only — no credentials. Use list_data_sources or get_data_source tools for filtered access.",
    20→		MIMEType:    "application/json",
    21→	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
