    27→		entries := make([]map[string]any, 0, len(list.Items))
    28→		for _, ds := range list.Items {
    29→			envVarNames := make([]string, 0, len(ds.Spec.EnvVarMapping))
    30→			for _, v := range ds.Spec.EnvVarMapping {
    31→				envVarNames = append(envVarNames, v)
