     1→// Package orgstandards loads and serves organisation coding standards.
     2→// Standards are read from a YAML or JSON file at startup and hot-reloaded
     3→// via fsnotify whenever the file changes.  If no file is configured or the
     4→// file cannot be read, compile-time platform defaults are served instead.
     5→package orgstandards
     6→
     7→import (
     8→	"context"
     9→	"encoding/json"
    10→	"fmt"
    11→	"io"
