    18→	"github.com/fsnotify/fsnotify"
    19→	"gopkg.in/yaml.v3"
    20→)
    21→
    22→const maxFileSize = 1 << 20 // 1 MB
    23→
    24→// PerLanguageStandards holds language-specific notes and library recommendations.
    25→type PerLanguageStandards struct {
    26→	Notes            []string          `json:"notes"            yaml:"notes"`
    27→	ApprovedLibraries map[string]string `json:"approvedLibraries" yaml:"approvedLibraries"`
    28→}
