    81→// Loader reads org standards from a file and provides a goroutine-safe Get().
    82→type Loader struct {
    83→	path    string
    84→	mu      sync.RWMutex
    85→	current *OrgStandards
    86→	logger  *slog.Logger
    87→}
    88→
    89→// New creates a Loader.  path may be empty, in which case platform defaults
    90→// are always returned.  Call Start to begin watching the file for changes.
    91→func New(path string, logger *slog.Logger) *Loader {
    92→	if logger == nil {
    93→		logger = slog.Default()
    94→	}
    95→	l := &Loader{path: path, logger: logger}
    96→	l.current = l.load()
    97→	return l
    98→}
    99→
   100→// Get returns the current standards.  Safe for concurrent use.
   101→func (l *Loader) Get() *OrgStandards {
   102→	l.mu.RLock()
   103→	defer l.mu.RUnlock()
   104→	return l.current
   105→}
   106→
   107→// Start begins watching the config file for changes.  It blocks until ctx is
   108→// cancelled.  Safe to call in a goroutine.
   109→func (l *Loader) Start(ctx context.Context) {
   110→	if l.path == "" {
   111→		return
   112→	}
   113→
   114→	watcher, err := fsnotify.NewWatcher()
   115→	if err != nil {
   116→		l.logger.Warn("orgstandards: cannot create file watcher", "error", err)
   117→		return
   118→	}
   119→	defer watcher.Close()
   120→
   121→	// Watch the directory so renames/atomic writes are detected.
   122→	dir := filepath.Dir(l.path)
   123→	if err := watcher.Add(dir); err != nil {
   124→		l.logger.Warn("orgstandards: cannot watch directory", "dir", dir, "error", err)
   125→		return
   126→	}
   127→
   128→	for {
   129→		select {
   130→		case <-ctx.Done():
   131→			return
   132→		case event, ok := <-watcher.Events:
   133→			if !ok {
   134→				return
   135→			}
   136→			if event.Name != l.path {
   137→				continue
   138→			}
   139→			if event.Has(fsnotify.Write) || event.Has(fsnotify.Create) {
   140→				updated := l.load()
   141→				l.mu.Lock()
   142→				l.current = updated
   143→				l.mu.Unlock()
   144→				l.logger.Info("orgstandards: reloaded", "path", l.path)
   145→			}
   146→		case err, ok := <-watcher.Errors:
   147→			if !ok {
   148→				return
   149→			}
   150→			l.logger.Warn("orgstandards: watcher error", "error", err)
   151→		}
   152→	}
   153→}
   154→
   155→// load reads and parses the config file, returning platform defaults on any error.
   156→func (l *Loader) load() *OrgStandards {
   157→	if l.path == "" {
   158→		return platformDefaults()
   159→	}
   160→
   161→	// Defence-in-depth: reject paths with traversal sequences.
   162→	clean := filepath.Clean(l.path)
   163→	if strings.Contains(clean, "..") {
   164→		l.logger.Warn("orgstandards: rejecting path with traversal", "path", l.path)
   165→		return platformDefaults()
   166→	}
   167→
   168→	f, err := os.Open(clean)
   169→	if err != nil {
   170→		if !os.IsNotExist(err) {
   171→			l.logger.Warn("orgstandards: cannot open file", "path", clean, "error", err)
   172→		}
   173→		return platformDefaults()
   174→	}
   175→	defer f.Close()
   176→
   177→	data, err := io.ReadAll(io.LimitReader(f, maxFileSize))
   178→	if err != nil {
   179→		l.logger.Warn("orgstandards: read error", "path", clean, "error", err)
   180→		return platformDefaults()
   181→	}
   182→
   183→	var standards OrgStandards
   184→	ext := strings.ToLower(filepath.Ext(clean))
   185→	if ext == ".json" {
   186→		err = json.Unmarshal(data, &standards)
   187→	} else {
   188→		// Default: YAML (also accepts .yaml, .yml, anything else).
   189→		err = yaml.Unmarshal(data, &standards)
   190→	}
   191→	if err != nil {
   192→		l.logger.Warn("orgstandards: parse error — retaining previous", "path", clean, "error", err)
   193→		return l.Get() // retain current value on parse failure
   194→	}
   195→
   196→	// Ensure slices are non-nil for clean JSON output.
   197→	if standards.RequiredEnvVars == nil {
   198→		standards.RequiredEnvVars = []string{}
   199→	}
   200→	if standards.BestPractices == nil {
   201→		standards.BestPractices = []string{}
   202→	}
   203→	if standards.PerLanguage == nil {
   204→		standards.PerLanguage = map[string]PerLanguageStandards{}
   205→	}
   206→
   207→	l.logger.Info("orgstandards: loaded", "path", clean)
   208→	return &standards
   209→
   210→}
