    13→// RegisterDataCatalog registers the iaf://catalog/data-sources MCP resource.
    14→// Returns a JSON index of all cluster-registered DataSources. No credential data is included.
    15→func RegisterDataCatalog(server *gomcp.Server, deps *tools.Dependencies) {
    16→	server.AddResource(&gomcp.Resource{
    17→		URI:         "iaf://catalog/data-sources",
    18→		Name:        "data-catalog",
    19→		Description: "JSON index of all data sources registered on the platform. Contains metadata only — no credentials. Use list_data_sources or get_data_source tools for filtered access.",
    20→		MIMEType:    "application/json",
    21→	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
    22→		var list iafv1alpha1.DataSourceList
    23→		if err := deps.Client.List(ctx, &list); err != nil {
    24→			return nil, fmt.Errorf("listing data sources: %w", err)
    25→		}
    26→
    27→		entries := make([]map[string]any, 0, len(list.Items))
    28→		for _, ds := range list.Items {
    29→			envVarNames := make([]string, 0, len(ds.Spec.EnvVarMapping))
    30→			for _, v := range ds.Spec.EnvVarMapping {
    31→				envVarNames = append(envVarNames, v)
    32→			}
    33→			entry := map[string]any{
    34→				"name":        ds.Name,
    35→				"kind":        ds.Spec.Kind,
    36→				"envVarNames": envVarNames,
    37→			}
    38→			if ds.Spec.Description != "" {
    39→				entry["description"] = ds.Spec.Description
    40→			}
    41→			if ds.Spec.Schema != "" {
    42→				entry["schema"] = ds.Spec.Schema
    43→			}
    44→			if len(ds.Spec.Tags) > 0 {
    45→				entry["tags"] = ds.Spec.Tags
    46→			}
    47→			entries = append(entries, entry)
    48→		}
    49→
    50→		payload := map[string]any{
    51→			"dataSources": entries,
    52→			"total":       len(entries),
    53→			"note":        "Credential values are never included. Use attach_data_source to make a data source available to your app.",
    54→		}
    55→		data, err := json.MarshalIndent(payload, "", "  ")
    56→		if err != nil {
    57→			return nil, fmt.Errorf("marshaling data catalog: %w", err)
    58→		}
    59→
    60→		return &gomcp.ReadResourceResult{
    61→			Contents: []*gomcp.ResourceContents{
    62→				{URI: req.Params.URI, MIMEType: "application/json", Text: string(data)},
    63→			},
    64→		}, nil
    65→	})
    66→}
