   282→func setupServerForLogs(t *testing.T, withClientset bool) (*gomcp.ClientSession, ctrlclient.Client) {
   283→	t.Helper()
   284→	ctx := context.Background()
   285→
   286→	scheme := runtime.NewScheme()
   287→	_ = iafv1alpha1.AddToScheme(scheme)
   288→	_ = corev1.AddToScheme(scheme)
   289→	k8sClient := fake.NewClientBuilder().WithScheme(scheme).Build()
   290→
   291→	store, err := sourcestore.New(t.TempDir(), "http://localhost:8080", slog.Default())
   292→	if err != nil {
   293→		t.Fatal(err)
   294→	}
   295→	sessions, err := auth.NewSessionStore(filepath.Join(t.TempDir(), "sessions.json"))
   296→	if err != nil {
   297→		t.Fatal(err)
   298→	}
   299→
   300→	var server *gomcp.Server
   301→	if withClientset {
   302→		cs := k8sfake.NewSimpleClientset()
   303→		server = iafmcp.NewServer(k8sClient, sessions, store, "test.example.com", nil, nil, "", "", "", cs)
   304→	} else {
   305→		server = iafmcp.NewServer(k8sClient, sessions, store, "test.example.com", nil, nil, "", "", "")
   306→	}
   307→
   308→	st, ct := gomcp.NewInMemoryTransports()
   309→	if _, err := server.Connect(ctx, st, nil); err != nil {
   310→		t.Fatal(err)
   311→	}
   312→	client := gomcp.NewClient(&gomcp.Implementation{Name: "test-client", Version: "0.0.1"}, nil)
   313→	clientSession, err := client.Connect(ctx, ct, nil)
   314→	if err != nil {
   315→		t.Fatal(err)
   316→	}
   317→	t.Cleanup(func() { clientSession.Close() })
   318→	return clientSession, k8sClient
   319→}
